############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.8.5) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGgraphmacros.pl", "contextFiniteSolutionSets.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $a = random(1,3,1); $gr = init_graph(-1,-1,4,4, axes=>[0,0], grid=>[5,5], size=>[300,180] ); add_functions($gr, "x^3/$a^3 for x in <-1,4> using color:blue and weight:2"); $second_x = Real($a*2**(1/3)); $solgr = init_graph(-1,-1,4,4, axes=>[0,0], grid=>[5,5], size=>[300,180] ); add_functions($solgr, "x^3/$a^3 for x in <-1,4> using color:blue and weight:2"); $solgr->moveTo(0,1); $solgr->lineTo($a,1,'black',3); $solgr->arrowTo($a,0,'black',3); Context("FiniteSolutionSets"); $answer = Formula("{$a}");
############################################################ # Body ############################################################
BEGIN_PGML The graph below is a graph of [`y=f(x)\text{.}`] Use the graph to solve the equation [`f(x)=1\text{.}`]
>> [@image(insertGraph($gr), width=>300, alt=>qq"a plot of a curve on a cartesian set of axes; the x axis ranges from -1 to 4, and the y-axis ranges from -1 to 4; the curve enters from the left, below the x-axis, and curves upward and to the right until it reaches the point (0,0); from here it continues predominantly rightward for a bit, bending slightly upward more and more as it progresses; it passes through the points ($a,1) and ($second_x,2) before leaving the graph moving more and more upward and to the right.")@]* <<
[_]{$answer}{5} [@AnswerFormatHelp('numbers')@]*
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The graph reveals that the solution set to [`f(x)=1`] is [`[$answer]\text{.}`]
>> [@image(insertGraph($solgr), width=>300, alt=>qq"a plot of a curve on a cartesian set of axes; the x axis ranges from -1 to 4, and the y-axis ranges from -1 to 4; the curve enters from the left, below the x-axis, and curves upward and to the right until it reaches the point (0,0); from here it continues predominantly rightward for a bit, bending slightly upward more and more as it progresses; it passes through the points ($a,1) and ($second_x,2) before leaving the graph moving more and more upward and to the right; a horizontal line segment moves rightward from y=1 on the y-axis until it reaches a point on the curve; a vertical line segment moves down from this point to x=$a on the x-axis.")@]* <<
END_PGML_SOLUTION
############################################################ # End Problem ############################################################
ENDDOCUMENT();
